int[] maxOccurrence(int[][] intervals) {
        int[] ans = new int[2];
        Arrays.sort(intervals, (a, b) -> a[0] == b[0]? b[1] - a[1]: a[0] - b[0]);
        int max = 0;
        BIT bit = new BIT(100000);

        for (int i = 0; i < intervals.length; i++) {
            int cur = i-bit.query(intervals[i][1]-1) ;
            if(cur > max) {
                max = cur;
                ans = intervals[i];
            }
            bit.update(intervals[i][1], 1);
        }
        return ans;
    }

class BIT {
        int[] tree;
        int n;
        public BIT(int n) {
            this.n = n;
            tree = new int[n+1];
        }

        public void update(int i, int val) {
            i += 1;
            while(i <= n) {
                tree[i] += val;
                i += i & (-i);
            }
        }

        public int query(int i) {
            int q = i;
            i += 1;
            int ans = 0;
            while(i > 0) {
                ans += tree[i];
                i -= i & (-i);
            }
            return ans;
        }
    }
